#include <stdio.h>
#include <stdlib.h>

// Function to query the segment tree
void query(int node, int start, int end, int l, int r, int* cnt) {
    if (start > r || end < l) return;
    if (start >= l && end <= r) {
        (*cnt)++;
        return;
    }
    int mid = (start + end) / 2;
    query(2 * node, start, mid, l, r, cnt);
    query(2 * node + 1, mid + 1, end, l, r, cnt);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int* cnt = (int*) malloc((N + 1) * sizeof(int));
        for (int i = 1; i <= N; i++) cnt[i] = 0;
        for (int i = 1; i <= N; i++) {
            for (int j = i; j <= N; j++) {
                int temp = 0;
                query(1, 1, N, i, j, &temp);
                cnt[temp]++;
            }
        }
        int k = 0;
        for (int i = 1; i <= N; i++) if (cnt[i] > 0) k++;
        printf("%d\n", k);
        for (int i = 1; i <= N; i++) if (cnt[i] > 0) printf("%d\n", cnt[i]);
    }
    return 0;
}

